1659:     /**
1660:      * Converts this config into an HTML list that can be embedded into docs.
1661:      * If <code>dynamicUpdateModes</code> is non-empty, a "Dynamic Update Mode" label
1662:      * will be included in the config details with the value of the update mode. Default
1663:      * mode is "read-only".
1664:      * @param headerDepth The top level header depth in the generated HTML.
1665:      * @param idGenerator A function for computing the HTML id attribute in the generated HTML from a given config name.
1666:      * @param dynamicUpdateModes Config name -&gt; update mode mapping.
1667:      */
1668:     public String toHtml(int headerDepth, Function<String, String> idGenerator,
1669:                          Map<String, String> dynamicUpdateModes) {
1670:         boolean hasUpdateModes = !dynamicUpdateModes.isEmpty();
1671:         List<ConfigKey> configs = sortedConfigs();
1672:         StringBuilder b = new StringBuilder();
1673:         b.append("<ul class=\"config-list\">\n");
1674:         for (ConfigKey key : configs) {
1675:             if (key.internalConfig) {
1676:                 continue;
1677:             }
1678:             b.append("<li>\n");
1679:             b.append(String.format("<h%1$d>" +
1680:                     "<a id=\"%3$s\"></a><a id=\"%2$s\" href=\"#%2$s\">%3$s</a>" +
1681:                     "</h%1$d>%n", headerDepth, idGenerator.apply(key.name), key.name));
1682:             b.append("<p>");
1683:             if (key.documentation != null) {
1684:                 b.append(key.documentation.replaceAll("\n", "<br>"));
1685:             }
1686:             b.append("</p>\n");
1687: 
1688:             b.append("<table>" +
1689:                     "<tbody>\n");
1690:             for (String detail : headers()) {
1691:                 if (detail.equals("Name") || detail.equals("Description")) continue;
1692:                 if (detail.equals("Default") && key.alternativeString != null) {
1693:                     addConfigDetail(b, detail, key.alternativeString);
1694:                     continue;
1695:                 }
1696:                 addConfigDetail(b, detail, getConfigValue(key, detail));
1697:             }
1698:             if (hasUpdateModes) {
1699:                 String updateMode = dynamicUpdateModes.get(key.name);
1700:                 if (updateMode == null)
1701:                     updateMode = "read-only";
1702:                 addConfigDetail(b, "Update Mode", updateMode);
1703:             }
1704:             b.append("</tbody></table>\n");
1705:             b.append("</li>\n");
1706:         }
1707:         b.append("</ul>\n");
1708:         return b.toString();
1709:     }
